SELECT season_name, AVG(prize_pool) AS avg_prize_pool
FROM seasons
GROUP BY season_name;

SELECT SUM(wins) AS total_wins
FROM team_stats
WHERE season_id = 1;

SELECT COUNT(team_id) AS total_teams
FROM season_teams
WHERE season_id = 1;

SELECT season_name
FROM seasons
ORDER BY start_date ASC;

SELECT AVG(prize_pool) AS average_prize_pool
FROM seasons
WHERE season_id IN (
  SELECT season_id
  FROM season_teams
);

SELECT season_name
FROM seasons
WHERE season_id = 1;
